+#[derive(Debug, Clone, PartialEq, Eq, Hash)]
+struct DiscoverySessionFingerprintMaterial {
+    local_node: NodeId,
+    peer_node: NodeId,
+    bootstrap_key: String,
+    policy_version: u64,
+    credential_subject: NodeId,
+    credential_issuer: NodeId,
